```rust
impl SpecificCSSRule for {RuleType} {
    fn ty(&self) -> CssRuleType {
        CssRuleType::{Variant}
    }

    fn get_css(&self) -> DOMString {
        let guard = self.cssconditionrule.shared_lock().read();
        self.{rule_field}.borrow().to_css_string(&guard).into()
    }
}
```

